@namespace
class SpriteKind:
    Item = SpriteKind.create()

def on_on_overlap(sprite, otherSprite):
    info.change_score_by(1)
    sprites.destroy_all_sprites_of_kind(SpriteKind.Item, effects.none, 1)
    music.stop_all_sounds()
    music.play(music.melody_playable(music.power_up),
        music.PlaybackMode.UNTIL_DONE)
    info.change_countdown_by(15)
sprites.on_overlap(SpriteKind.player, SpriteKind.Item, on_on_overlap)

def on_b_pressed():
    mySprite2.follow(mySprite, 40)
controller.B.on_event(ControllerButtonEvent.PRESSED, on_b_pressed)

def on_a_pressed():
    mySprite2.follow(mySprite, 60)
controller.A.on_event(ControllerButtonEvent.PRESSED, on_a_pressed)

def on_countdown_end():
    if info.score() < 25:
        game.game_over(False)
        music.play(music.melody_playable(music.small_crash),
            music.PlaybackMode.UNTIL_DONE)
    else:
        game.game_over(True)
info.on_countdown_end(on_countdown_end)

def on_on_overlap2(sprite2, otherSprite2):
    mySprite.set_position(80, 103)
    info.change_life_by(-1)
    music.stop_all_sounds()
    music.play(music.melody_playable(music.power_down),
        music.PlaybackMode.UNTIL_DONE)
    info.change_countdown_by(-20)
sprites.on_overlap(SpriteKind.player, SpriteKind.enemy, on_on_overlap2)

def on_life_zero():
    if info.score() < 25:
        game.game_over(False)
        music.play(music.melody_playable(music.big_crash),
            music.PlaybackMode.UNTIL_DONE)
    else:
        game.game_over(True)
info.on_life_zero(on_life_zero)

